import React from "react";

function VendedorDashboard() {
  return (
    <div style={{ padding: "20px" }}>
      <h2>Panel de Vendedor</h2>
      <p>Aquí verás tus productos, pedidos y estadísticas de ventas.</p>
    </div>
  );
}

export default VendedorDashboard;
